-- ============================================================================
-- seed_matches.sql — Inserta los 104 partidos del Mundial 2026 en la tabla matches.
-- Ejecutar DESPUES de migrate_v2.sql. Es idempotente (usa ON CONFLICT).
-- ============================================================================

ON CONFLICT (id) DO UPDATE SET
  home_team  = EXCLUDED.home_team,
  away_team  = EXCLUDED.away_team,
  group_key  = EXCLUDED.group_key,
  stage      = EXCLUDED.stage,
  kickoff    = EXCLUDED.kickoff,
  venue      = EXCLUDED.venue;

-- Verificacion: contar partidos insertados
SELECT
  count(*) as total_matches,
  count(*) filter (where group_key is not null) as group_stage,
  count(*) filter (where stage is not null) as knockout
FROM public.matches;
